using namespace std;

struct Node {
  int data;
  Node* next;
  Node* prev;
  Node(int d) { data = d; }
};

class Solution {
  public:   bool sortList(Node* head, int n) {
    if (n <= 1) return true;
    Node* cur = head;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) arr[i] = cur->data;
    sort(arr.begin(), arr.end());
    cur = head;
    for (int i = 0; i < n; i++) cur->data = arr[i];
    return true;
  }
};

